import datetimeimport uuidfrom typing import Optionalfrom sqlalchemy import TIMESTAMP, TEXT, VARCHAR, BOOLEAN, UUIDfrom sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelclass PlatformMatchInteractionModel(BaseModel):    __tablename__ = 'platform_match_interaction'    id: Mapped[uuid.UUID] = mapped_column(UUID, primary_key=True)    from_user_id: Mapped[uuid.UUID] = mapped_column(UUID)    to_user_id: Mapped[uuid.UUID] = mapped_column(UUID)    action: Mapped[Optional[str]] = mapped_column(VARCHAR(20), comment="""interest/skip/save/block""")    message: Mapped[Optional[str]] = mapped_column(TEXT, comment="""表达兴趣时附带的消息""")    is_mutual: Mapped[Optional[bool]] = mapped_column(BOOLEAN, comment="""0 - 未开始，刚添加(单向关注)，1-双向兴趣 → 2. 解锁私信 代表配对成功""")    created_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP)    result_id: Mapped[uuid.UUID] = mapped_column(UUID)    need_id: Mapped[uuid.UUID] = mapped_column(UUID)    type: Mapped[Optional[str]] = mapped_column(VARCHAR(100))